clc; 
%% LOAD DATA
firePath = 'Put the fire dataset path';
imds_fire = imageDatastore(firePath, ...
    'IncludeSubfolders', true, ...
    'LabelSource', 'foldernames');

disp(countEachLabel(imds_fire)) %[output:8da9d4a7]

%% SPLIT DATA
[train_fire, val_fire] = splitEachLabel(imds_fire, 0.8, 'randomized');

%% IMAGE SIZE
inputSize = [224 224 3];
train_fire_aug = augmentedImageDatastore(inputSize, train_fire, ...
    'ColorPreprocessing','gray2rgb'); 

val_fire_aug = augmentedImageDatastore(inputSize, val_fire, ...
    'ColorPreprocessing','gray2rgb');   

%% LOAD RESNET
net = resnet18;
lgraph = layerGraph(net);
numClasses = numel(categories(imds_fire.Labels));
lgraph = replaceLayer(lgraph, lgraph.Layers(end-2).Name, ...
    fullyConnectedLayer(numClasses));
lgraph = replaceLayer(lgraph, lgraph.Layers(end-1).Name, softmaxLayer);
lgraph = replaceLayer(lgraph, lgraph.Layers(end).Name, classificationLayer);

% TRAIN OPTIONS
options = trainingOptions('adam', ...
    'MaxEpochs', 5, ...
    'MiniBatchSize', 16, ...
    'ValidationData', val_fire_aug, ...
    'Verbose', false, ...
    'Plots', 'training-progress');

%% TRAIN
disp("Training Fire Model...") %[output:62726f52]
fireNet = trainNetwork(train_fire_aug, lgraph, options); %[output:1b8b9e16]
fireModel = fireNet;
save('fireModel.mat', 'fireModel');


